script:
const { query, session, overlay, context } = scope;

const streetSearch = query.toLowerCase();
const group = session.groups.find(g => g.name === 'Parking Spaces');
const points = session.points[group.id].filter(p => p.properties[2].toLowerCase().includes(streetSearch));
overlay({
  message: `Found Parking Lots:
	${points.map(p => p.properties[2] + ' - ' + p.properties[1] + ' spaces').join(', \n')}.
  `,
  confirmText: 'Navigate To The Biggest One',
  confirmAction: () => {
  	const lot = points.reduce((best, current) =>
      Number(current.properties[1]) > Number(best.properties[1]) ? current : best
    );
    context.methods.goToCoordinates(lot.coordinates, 20);
  }
});
